const express = require('express');
const multer = require('multer');
const libxmljs = require('libxmljs');
const app = express();

const upload = multer({ dest: 'uploads/' });

app.post('/upload-xml', upload.single('xmlFile'), (req, res) => {
  if (!req.file) {
    return res.status(400).json({ error: 'No file uploaded' });
  }

  try {
    const xmlContent = req.file.buffer.toString('utf8');
    
    const options = {
      noent: true,
      noblank: true,
      nsclean: true,
      nonet: true,
      noent: true,
      nocdata: true
    };

    const xmlDoc = libxmljs.parseXml(xmlContent, options);
    
    const config = {};
    
    const extractElements = (node) => {
      const result = {};
      
      if (node.type() === 'element') {
        const children = node.childNodes();
        
        if (children.length === 0) {
          result[node.name()] = node.text();
        } else {
          result[node.name()] = {};
          children.forEach(child => {
            if (child.type() === 'element') {
              const childResult = extractElements(child);
              Object.assign(result[node.name()], childResult);
            }
          });
        }
      }
      
      return result;
    };
    
    const root = xmlDoc.root();
    const extractedConfig = extractElements(root);
    
    res.json({
      success: true,
      config: extractedConfig,
      fileName: req.file.originalname
    });
    
  } catch (error) {
    res.status(400).json({ 
      error: 'Invalid XML or parsing error',
      message: error.message 
    });
  }
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});